114	fn collect_functions_from_path(
115	    path: &Path,
116	    exclude_set: &GlobSet,
117	    functions: &mut Vec<FunctionInfo>,
118	    errors: &mut Vec<String>,
119	) {
120	    if path.is_file() {
121	        if should_skip(path, exclude_set) {
