132	                    if should_skip(ep, exclude_set) {
133	                        continue;
134	                    }
135	                    if e.file_type().is_file()
136	                        && ep.extension().and_then(|x| x.to_str()) == Some("rs")
137	                    {
138	                        process_file(ep, functions, errors);
139	                    }
140	                }
141	                Err(err) => {
142	                    errors.push(format!("walk error: {}", err));
143	                }
144	            }
