156	fn process_file(path: &Path, functions: &mut Vec<FunctionInfo>, errors: &mut Vec<String>) {
157	    let source = match std::fs::read_to_string(path) {
158	        Ok(s) => s,
159	        Err(e) => {
160	            errors.push(format!("cannot read {}: {}", path.display(), e));
161	            return;
162	        }
163	    };
164	
165	    let mut parser = tree_sitter::Parser::new();
166	    parser
167	        .set_language(&tree_sitter_rust::LANGUAGE.into())
168	        .expect("failed to load Rust grammar");
169	
170	    let tree = match parser.parse(&source, None) {
171	        Some(t) => t,
172	        None => {
173	            errors.push(format!("parse returned None for {}", path.display()));
174	            return;
175	        }
176	    };
177	
178	    if tree.root_node().has_error() {
179	        errors.push(format!("parse error in {}", path.display()));
180	        return;
181	    }
182	
183	    let file_str = path.to_string_lossy().to_string();
184	    extract_functions(tree.root_node(), &source, &file_str, functions);
