187	fn extract_functions(
188	    node: tree_sitter::Node,
189	    source: &str,
190	    file: &str,
191	    functions: &mut Vec<FunctionInfo>,
192	) {
193	    match node.kind() {
194	        "function_item" => {
195	            let info = make_function_info(node, source, file);
196	            functions.push(info);
197	        }
198	        "let_declaration" => {
199	            if let Some(val) = find_child_by_field(node, "value") {
200	                if val.kind() == "closure_expression" {
201	                    let info = make_function_info(node, source, file);
202	                    functions.push(info);
203	                }
204	            }
205	            let mut cursor = node.walk();
206	            let children: Vec<_> = node.children(&mut cursor).collect();
207	            for child in children {
208	                if child.kind() != "closure_expression" {
209	                    extract_functions(child, source, file, functions);
210	                }
211	            }
212	        }
213	        _ => {
214	            let mut cursor = node.walk();
215	            let children: Vec<_> = node.children(&mut cursor).collect();
216	            for child in children {
217	                extract_functions(child, source, file, functions);
218	            }
219	        }
220	    }
221	}
