248	fn normalize_node_text(node: tree_sitter::Node, source: &str) -> String {
249	    match node.kind() {
250	        "identifier" | "field_identifier" | "type_identifier" | "lifetime" => "_ID".to_string(),
251	        "integer_literal" | "float_literal" | "string_literal" | "raw_string_literal"
252	        | "char_literal" | "boolean_literal" => "_LIT".to_string(),
253	        _ => {
254	            let start = node.start_byte();
255	            let end = node.end_byte();
256	            source[start..end].to_string()
257	        }
