261	fn build_normalized_subtree(node: tree_sitter::Node, source: &str) -> String {
262	    if node.child_count() == 0 {
263	        return normalize_node_text(node, source);
264	    }
265	    let mut parts = vec![format!("({}:", node.kind())];
266	    let mut cursor = node.walk();
267	    for child in node.children(&mut cursor) {
268	        parts.push(build_normalized_subtree(child, source));
269	    }
270	    parts.push(")".to_string());
271	    parts.join("")
272	}
