288	fn collect_hashes_recursive(node: tree_sitter::Node, source: &str, hashes: &mut Vec<u64>) {
289	    let subtree = build_normalized_subtree(node, source);
290	    hashes.push(hash_str(&subtree));
291	    let mut cursor = node.walk();
292	    for child in node.children(&mut cursor) {
