297	fn jaccard(a: &[u64], b: &[u64]) -> f64 {
298	    if a.is_empty() && b.is_empty() {
299	        return 1.0;
300	    }
301	    let set_a: HashSet<u64> = a.iter().copied().collect();
302	    let set_b: HashSet<u64> = b.iter().copied().collect();
303	    let intersection = set_a.intersection(&set_b).count();
304	    let union = set_a.union(&set_b).count();
305	    if union == 0 {
306	        return 0.0;
307	    }
308	    intersection as f64 / union as f64
309	}
