315	fn find_duplicate_pairs(
316	    functions: &[FunctionInfo],
317	    threshold: f64,
318	    min_lines: usize,
319	    min_nodes: usize,
320	) -> Vec<DuplicatePair> {
321	    let candidates: Vec<&FunctionInfo> = functions
322	        .iter()
323	        .filter(|f| source_lines(f) >= min_lines && f.node_hashes.len() >= min_nodes)
324	        .collect();
325	
326	    let mut pairs: Vec<DuplicatePair> = Vec::new();
327	
328	    for i in 0..candidates.len() {
329	        for j in (i + 1)..candidates.len() {
330	            let a = candidates[i];
331	            let b = candidates[j];
332	            if a.file == b.file && a.start_line == b.start_line {
333	                continue;
334	            }
335	            let score = jaccard(&a.node_hashes, &b.node_hashes);
336	            if score >= threshold {
337	                let (left, right) = order_endpoints(a, b);
338	                pairs.push(DuplicatePair {
339	                    score,
340	                    left: PairEndpoint {
341	                        file: left.file.clone(),
342	                        start_line: left.start_line,
343	                        end_line: left.end_line,
344	                        nodes: left.node_hashes.len(),
345	                    },
346	                    right: PairEndpoint {
347	                        file: right.file.clone(),
348	                        start_line: right.start_line,
349	                        end_line: right.end_line,
350	                        nodes: right.node_hashes.len(),
351	                    },
352	                });
353	            }
354	        }
355	    }
356	
357	    pairs.sort_by(|a, b| {
358	        b.score
359	            .partial_cmp(&a.score)
360	            .unwrap_or(std::cmp::Ordering::Equal)
361	            .then_with(|| a.left.file.cmp(&b.left.file))
362	            .then_with(|| a.left.start_line.cmp(&b.left.start_line))
363	            .then_with(|| a.right.file.cmp(&b.right.file))
364	            .then_with(|| a.right.start_line.cmp(&b.right.start_line))
365	    });
366	
367	    pairs
368	}
