370	fn order_endpoints<'a>(
371	    a: &'a FunctionInfo,
372	    b: &'a FunctionInfo,
373	) -> (&'a FunctionInfo, &'a FunctionInfo) {
374	    let cmp = a
375	        .file
376	        .cmp(&b.file)
377	        .then_with(|| a.start_line.cmp(&b.start_line));
378	    if cmp == std::cmp::Ordering::Greater {
379	        (b, a)
380	    } else {
381	        (a, b)
382	    }
383	}
