            right: PairEndpoint {
                file: "b.rs".to_string(),
                start_line: 1,
                end_line: 5,
                nodes: 10,
            },
        };
        let output = format_text(&[pair]);
        assert!(output.contains("DUPLICATE score="));
        assert!(output.contains("a.rs"));
        assert!(output.contains("b.rs"));
    }
}

