121	fn collect_functions_from_path(
122	    path: &Path,
123	    exclude_set: &GlobSet,
124	    functions: &mut Vec<FunctionInfo>,
125	    errors: &mut Vec<String>,
126	) {
127	    if path.is_file() {
128	        if should_skip(path, exclude_set) {
129	            return;
130	        }
131	        if path.extension().and_then(|e| e.to_str()) == Some("rs") {
132	            process_file(path, functions, errors);
133	        }
134	    } else {
135	        for entry in WalkDir::new(path).sort_by_file_name() {
136	            match entry {
137	                Ok(e) => {
138	                    let ep = e.path();
139	                    if should_skip(ep, exclude_set) {
140	                        continue;
141	                    }
142	                    if e.file_type().is_file()
143	                        && ep.extension().and_then(|x| x.to_str()) == Some("rs")
144	                    {
145	                        process_file(ep, functions, errors);
146	                    }
147	                }
148	                Err(err) => {
149	                    errors.push(format!("walk error: {}", err));
